export interface GgNode {
  id: string;
  type: string;
  labels: readonly string[];
  properties: Record<string, string>;
}

export interface GgEdge {
  from: string;
  to: string;
  source: string;
  target: string;
  sourceIds: readonly string[];
  targetIds: readonly string[];
  type: string;
  properties: Record<string, string>;
}

export interface GgProgram {
  nodes: readonly GgNode[];
  edges: readonly GgEdge[];
}

export interface GgTopologyState {
  nodeId: string;
  beta1: number;
  depth?: number;
  [key: string]: any;
}

export interface GgTemporalModelOptions {
  [key: string]: any;
}

export interface NamedPredicate<TState = GgTopologyState> {
  name: string;
  test: (state: TState) => boolean;
  predicate?: (state: TState) => boolean;
}

export interface CheckerOptions<TState = GgTopologyState> {
  invariants?: readonly NamedPredicate<TState>[];
  eventuals?: readonly NamedPredicate<TState>[];
  [key: string]: any;
}

export interface CheckerTopologyStats {
  forkCount: number;
  foldCount: number;
  ventCount: number;
  beta1: number;
  depthLayers: number;
  frontierByLayer: readonly number[];
  wally: number;
  frontierDeficit: number;
  wallaceNumber: number;
  frontierFill: number;
  [key: string]: any;
}

export interface CheckerResult<TState = GgTopologyState> {
  ok: boolean;
  complete: boolean;
  stateCount: number;
  topology: CheckerTopologyStats;
  violations: Array<{
    kind: 'invariant' | 'eventual';
    name: string;
    message: string;
    trace: readonly any[];
  }>;
  states?: readonly TState[];
}

export function parseGgProgram(source: string): GgProgram;
export function checkGgProgram(sourceOrProgram: string | GgProgram, options?: CheckerOptions): CheckerResult;
export function getGgRootNodeIds(program: GgProgram): readonly string[];
export function getGgTerminalNodeIds(program: GgProgram): readonly string[];
export function buildGgTemporalModel(program: GgProgram, options?: GgTemporalModelOptions): any;
